+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user preferences and exposes methods
+ * to check whether a notification should be sent for a given user
+ * and notification type.
+ *
+ * Depends on:
+ * - PreferencesRepository for data access
+ * - UserRepository to verify user existence
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type { UserRepository } from '../repositories/user.repository.js';
+import type {
+  UserPreferences,
+  UpdateEmailPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import {
+  DEFAULT_EMAIL_PREFERENCES,
+  NOTIFICATION_TYPE_TO_CATEGORY,
+} from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(
+    private preferencesRepository: PreferencesRepository,
+    private userRepository: UserRepository,
+  ) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if the user has no preferences set.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.preferencesRepository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating default preferences if none exist.
+   * Throws if the user does not exist.
+   */
+  getOrCreatePreferences(userId: string): UserPreferences {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+
+    const user = this.userRepository.findById(userId);
+    if (!user) {
+      throw new Error(`User not found: ${userId}`);
+    }
+
+    this.logger.info(`Creating default preferences for user ${userId}`);
+    const now = new Date();
+    const preferences: UserPreferences = {
+      id: generatePreferencesId(),
+      userId,
+      email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    return this.preferencesRepository.save(preferences);
+  }
+
+  /**
+   * Update email notification preferences for a user.
+   * Creates default preferences first if none exist.
+   * Throws if the user does not exist.
+   */
+  updateEmailPreferences(
+    userId: string,
+    input: UpdateEmailPreferencesInput,
+  ): UserPreferences {
+    const preferences = this.getOrCreatePreferences(userId);
+
+    const updatedEmail = { ...preferences.email };
+
+    if (input.enabled !== undefined) {
+      updatedEmail.enabled = input.enabled;
+    }
+    if (input.frequency !== undefined) {
+      updatedEmail.frequency = input.frequency;
+    }
+    if (input.categories) {
+      updatedEmail.categories = {
+        ...updatedEmail.categories,
+        ...input.categories,
+      };
+    }
+
+    this.logger.info(`Updating email preferences for user ${userId}`);
+    return this.preferencesRepository.update(preferences.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    });
+  }
+
+  /**
+   * Check whether a notification of the given type should be sent to the user
+   * via the email channel.
+   *
+   * Returns true if:
+   * - The user has no preferences (defaults allow all notifications)
+   * - Email is enabled AND the category for the notification type is enabled
+   *
+   * Returns false if:
+   * - Email is globally disabled
+   * - The specific category is disabled
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const preferences = this.preferencesRepository.findByUserId(userId);
+
+    // No preferences set — default is to send all notifications
+    if (!preferences) {
+      return true;
+    }
+
+    // Master switch
+    if (!preferences.email.enabled) {
+      this.logger.debug(`Email disabled for user ${userId}`);
+      return false;
+    }
+
+    // Category check
+    const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
+    if (!preferences.email.categories[categoryKey]) {
+      this.logger.debug(
+        `Category ${categoryKey} disabled for user ${userId}`,
+      );
+      return false;
+    }
+
+    return true;
+  }
+}

