/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently supports email as the only channel, with per-category
 * opt-in/out and frequency settings.
 */

import type { NotificationType } from './notification.js';

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Master switch — when false, no emails are sent regardless of other settings. */
  enabled: boolean;
  /** How often email notifications are delivered. */
  frequency: 'immediate' | 'daily-digest' | 'weekly-digest';
  /** Per-category subscription toggles. */
  categories: {
    orderConfirmations: boolean;
    orderStatusUpdates: boolean;
    welcomeMessages: boolean;
    profileUpdates: boolean;
  };
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailNotificationPreferences['frequency'];
  categories?: Partial<EmailNotificationPreferences['categories']>;
}

/**
 * Default email preferences for new users — all notifications enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    orderConfirmations: true,
    orderStatusUpdates: true,
    welcomeMessages: true,
    profileUpdates: true,
  },
};

/**
 * Maps NotificationType to the corresponding category key in EmailNotificationPreferences.
 */
export const NOTIFICATION_TYPE_TO_CATEGORY: Record<
  NotificationType,
  keyof EmailNotificationPreferences['categories']
> = {
  'order:confirmation': 'orderConfirmations',
  'order:status-update': 'orderStatusUpdates',
  'user:welcome': 'welcomeMessages',
  'user:profile-updated': 'profileUpdates',
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailNotificationPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailNotificationPreferences,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and exposes methods
 * to check whether a notification should be sent for a given user
 * and notification type.
 *
 * Depends on:
 * - PreferencesRepository for data access
 * - UserRepository to verify user existence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  NOTIFICATION_TYPE_TO_CATEGORY,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns undefined if the user has no preferences set.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   * Throws if the user does not exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
      createdAt: now,
      updatedAt: now,
    };

    return this.preferencesRepository.save(preferences);
  }

  /**
   * Update email notification preferences for a user.
   * Creates default preferences first if none exist.
   * Throws if the user does not exist.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    const preferences = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...preferences.email };

    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.categories) {
      updatedEmail.categories = {
        ...updatedEmail.categories,
        ...input.categories,
      };
    }

    this.logger.info(`Updating email preferences for user ${userId}`);
    return this.preferencesRepository.update(preferences.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification of the given type should be sent to the user
   * via the email channel.
   *
   * Returns true if:
   * - The user has no preferences (defaults allow all notifications)
   * - Email is enabled AND the category for the notification type is enabled
   *
   * Returns false if:
   * - Email is globally disabled
   * - The specific category is disabled
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences set — default is to send all notifications
    if (!preferences) {
      return true;
    }

    // Master switch
    if (!preferences.email.enabled) {
      this.logger.debug(`Email disabled for user ${userId}`);
      return false;
    }

    // Category check
    const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
    if (!preferences.email.categories[categoryKey]) {
      this.logger.debug(
        `Category ${categoryKey} disabled for user ${userId}`,
      );
      return false;
    }

    return true;
  }
}

